import logging
import json
import re
import unicodedata
from typing import List, Dict, Any
from workerinterfaces import ExecutorInterface, ConnectorClient, ExecutionResult, HttpMethod

class PromptExecutor(ExecutorInterface):
    async def execute(self, logger: logging.Logger, connector_client: ConnectorClient, input: Dict[str, Any]) -> ExecutionResult:
        # Get the JSON_TABLE input; expected to be a JSON string or already parsed
        raw_json = input.get("JSON_TABLE")
        if raw_json is None:
            logger.error("Input JSON_TABLE is missing.")
            return ExecutionResult(400, {}, {"text": "Error: JSON_TABLE input is required."})

        # Parse the input JSON into a list of records
        try:
            # If input is string, parse it; if list/dict already, use as is
            if isinstance(raw_json, str):
                records = json.loads(raw_json)
            else:
                records = raw_json
            if not isinstance(records, list):
                raise ValueError("Input JSON must be an array of objects.")
        except Exception as e:
            logger.error(f"Failed to parse JSON_TABLE input: {str(e)}")
            return ExecutionResult(400, {}, {"text": f"Error parsing JSON_TABLE input: {str(e)}"})

        def is_non_latin(text: str) -> bool:
            for char in text:
                # Check if character is not Latin script
                if char.isalpha():
                    try:
                        name = unicodedata.name(char)
                        # Latin letters have 'LATIN' in their name
                        if "LATIN" not in name:
                            return True
                    except ValueError:
                        # Characters with no name treated as non-latin
                        return True
            return False

        def contains_english(text: str) -> bool:
            # Simple heuristic: Check for common English words or grammar patterns
            # Match presence of common English words or verb forms
            english_words = {"the", "and", "is", "are", "this", "that", "because", "which",
                             "with", "for", "was", "were", "will", "can", "have", "has",
                             "they", "you", "we", "but", "or", "not", "from", "as"}
            # Tokenize the text to words (case insensitive)
            words = re.findall(r"\b[a-zA-Z]{2,}\b", text.lower())
            matches = sum(1 for w in words if w in english_words)
            # If more than 1 English word found, likely English text
            return matches > 1

        def is_repetitive_pattern(text: str) -> bool:
            # Rule: Ignore if length <=3 or single letter/number
            stripped_text = text.strip()
            if len(stripped_text) <= 3:
                return False

            # Check if all characters are identical (e.g., "aaaaaa")
            if len(set(stripped_text)) == 1:
                return True

            # Check for repetitive mathematical like pattern: e.g., "1+1+1+1"
            # Pattern: sequence of digits/symbols repeated multiple times
            # We'll detect if the whole string matches repeated subpattern
            max_sub_length = min(5, len(stripped_text)//2)
            for sub_len in range(1, max_sub_length +1):
                subpattern = stripped_text[:sub_len]
                repetitions = len(stripped_text) // sub_len
                if subpattern * repetitions == stripped_text:
                    # Verify that subpattern is not a real word or meaningful pattern
                    # If subpattern is 1 char repeated, caught above already
                    # If subpattern contains only digits and mathematical symbols
                    if re.fullmatch(r"[\d\+\-\*/\^\.]+", subpattern):
                        return True

            return False

        for record in records:
            nota_cierre = record.get("Nota de Cierre", "")
            # Apply Step 1 conditions
            cond_a = False
            cond_b = False
            # Condition A: English sentences or non-Latin script
            if nota_cierre:
                if contains_english(nota_cierre):
                    cond_a = True
                elif is_non_latin(nota_cierre):
                    cond_a = True

                # Condition B: repetitive patterns excluding very short
                if not cond_a:  # Only check B if A not met
                    if is_repetitive_pattern(nota_cierre):
                        cond_b = True

            # Step 2: If any cond true, set fields accordingly
            if cond_a or cond_b:
                record["Estado de la Razón"] = "ERROR DE OTO"
                record["Razón Sugerida"] = "NO REQUIERE"
            else:
                # Do not modify "Estado de la Razón" or "Razón Sugerida"
                pass

        # Save the resulting JSON array to 'datos_auditados.json' (UTF-8)
        filename = 'datos_auditados.json'
        try:
            with open(filename, 'w', encoding='utf-8') as f:
                json.dump(records, f, ensure_ascii=False, indent=2)
            logger.info(f"Audit file '{filename}' written successfully.")
        except Exception as e:
            logger.error(f"Failed to write audit file: {str(e)}")
            return ExecutionResult(500, {}, {"text": f"Error writing audit results: {str(e)}"})

        # Return with files key per functional requirement, no base64 encoding or structure alteration
        return ExecutionResult(
            status_code=200,
            headers={},
            body={
                "files": [filename]
            }
        )
